import React, { useEffect, useState, useCallback, useMemo } from 'react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './HoSoCaNhan.css';

const fmt = (n) =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

export default function HoSoCaNhan() {
  const { user, layThongTinToi } = useAuthStore();

  // State
  const [activeTab, setActiveTab] = useState('caNhan'); // 'caNhan' hoặc 'congKhai'
  const [editing, setEditing] = useState(false);
  const [saving, setSaving] = useState(false);

  // Form cho Thông tin cá nhân
  const [formCaNhan, setFormCaNhan] = useState({
    hoTen: '',
    soDienThoai: '',
  });

  // Form cho Hồ sơ công khai
  const [formCongKhai, setFormCongKhai] = useState({
    gioiThieu: '',
    ngheNghiep: '',
    diaChi: '',
    ngaySinh: '',
    gioiTinh: '',
  });

  // ====================== Khởi tạo dữ liệu ======================
  const initialFormCaNhan = useMemo(() => ({
    hoTen: user?.hoTen || '',
    soDienThoai: user?.soDienThoai || '',
  }), [user]);

  const initialFormCongKhai = useMemo(() => ({
    gioiThieu: user?.gioiThieu || '',
    ngheNghiep: user?.ngheNghiep || '',
    diaChi: user?.diaChi || '',
    ngaySinh: user?.ngaySinh ? user.ngaySinh.split('T')[0] : '',
    gioiTinh: user?.gioiTinh || '',
  }), [user]);

  useEffect(() => {
    setFormCaNhan(initialFormCaNhan);
    setFormCongKhai(initialFormCongKhai);
  }, [initialFormCaNhan, initialFormCongKhai]);

  // ====================== Handlers ======================
  const handleSaveCaNhan = useCallback(async () => {
    setSaving(true);
    try {
      await nguoiDungAPI.capNhat(formCaNhan);
      await layThongTinToi();
      toast.success('Cập nhật thông tin cá nhân thành công!');
      setEditing(false);
    } catch {
      toast.error('Cập nhật thất bại');
    } finally {
      setSaving(false);
    }
  }, [formCaNhan, layThongTinToi]);

  const handleSaveCongKhai = useCallback(async () => {
    setSaving(true);
    try {
      await nguoiDungAPI.capNhatCongKhai?.(formCongKhai); // Giả sử API có hàm này
      // Nếu chưa có API riêng, bạn có thể dùng chung nguoiDungAPI.capNhat(formCongKhai)
      await layThongTinToi();
      toast.success('Cập nhật hồ sơ công khai thành công!');
      setEditing(false);
    } catch {
      toast.error('Cập nhật thất bại');
    } finally {
      setSaving(false);
    }
  }, [formCongKhai, layThongTinToi]);

  const handleAvatarChange = useCallback(async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const fd = new FormData();
    fd.append('file', file);

    try {
      await nguoiDungAPI.uploadAvatar(fd);
      await layThongTinToi();
      toast.success('Cập nhật ảnh đại diện thành công!');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Upload thất bại');
    }
  }, [layThongTinToi]);

  // ====================== Memoized Data ======================
  const quickActions = useMemo(() => [
    { to: '/quan-ly-phong', icon: '🏠', label: 'Quản lý phòng' },
    { to: '/yeu-cau', icon: '📋', label: 'Yêu cầu của tôi' },
    { to: '/thanh-toan', icon: '💰', label: 'Ví tiền' },
    { to: '/hoa-don', icon: '📄', label: 'Hóa đơn của tôi' },
    { to: '/tam-tru', icon: '📄', label: 'Phiếu tạm trú' },
    { to: '/danh-gia', icon: '⭐', label: 'Đánh giá' },
    { to: '/xac-thuc', icon: '🔐', label: 'Xác thực CCCD' },
  ], []);

  const infoCaNhan = useMemo(() => [
    ['👤 Họ tên', user?.hoTen],
    ['📧 Email', user?.email],
    ['📱 Điện thoại', user?.soDienThoai || 'Chưa cập nhật'],
    ['📅 Ngày tham gia', user?.ngayTao ? new Date(user.ngayTao).toLocaleDateString('vi-VN') : ''],
  ], [user]);

  if (!user) return <div className="spinner" />;

  return (
    <div className="container page-wrapper">
      <div className="hoso-layout">
        {/* Profile Card */}
        <div className="card profile-card">
          <div className="card-body" style={{ textAlign: 'center' }}>
            <div className="avatar-upload">
              <img
                src={user.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.hoTen)}&background=12355B&color=fff&size=120`}
                className="avatar avatar-xl"
                alt="Avatar"
                loading="lazy"
              />
              <label htmlFor="avatar-input" className="avatar-edit-btn" title="Đổi ảnh">✏️</label>
              <input id="avatar-input" type="file" accept="image/*" hidden onChange={handleAvatarChange} />
            </div>

            <h2 style={{ marginTop: 16, fontWeight: 800 }}>{user.hoTen}</h2>
            <Link to={`/nguoi-dung/${user.maNguoiDung}`} className="btn btn-outline btn-sm" style={{ marginTop: 12 }}>
              Xem trang công khai
            </Link>

            {user.xacThuc ? (
              <span className="badge badge-success" style={{ marginTop: 8 }}>✅ Đã xác thực CCCD</span>
            ) : (
              <Link to="/xac-thuc" className="badge badge-warning" style={{ marginTop: 8, cursor: 'pointer', textDecoration: 'none' }}>
                ⚠️ Chưa xác thực — Xác thực ngay
              </Link>
            )}

            <div style={{ marginTop: 14 }}>
              {user.diemDanhGia ? (
                <div className="stars">
                  {'★'.repeat(Math.round(user.diemDanhGia))}
                  {'☆'.repeat(5 - Math.round(user.diemDanhGia))}
                  <span style={{ fontSize: 14, color: 'var(--text-muted)', marginLeft: 6 }}>
                    {user.diemDanhGia.toFixed(1)} / 5
                  </span>
                </div>
              ) : (
                <div style={{ color: 'var(--text-muted)', fontSize: 14 }}>Chưa có đánh giá nào</div>
              )}
            </div>

            <div style={{ marginTop: 20, padding: '16px 0', borderTop: '1px solid var(--border)' }}>
              <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>Số dư ví</div>
              <div style={{ fontSize: 24, fontWeight: 800, color: 'var(--primary)' }}>{fmt(user.soDuVi)}</div>
              <div className="profile-wallet-actions">
                <Link to="/thanh-toan" className="btn btn-outline btn-sm">Nạp tiền</Link>
                <Link to="/hoa-don" className="btn btn-outline btn-sm">Hóa đơn</Link>
              </div>
            </div>
          </div>
        </div>

        <div>
          {/* Tab chuyển đổi */}
          <div className="card" style={{ marginBottom: 20 }}>
            <div className="card-header tabs">
              <button
                className={`tab-btn ${activeTab === 'caNhan' ? 'active' : ''}`}
                onClick={() => setActiveTab('caNhan')}
              >
                Thông tin cá nhân
              </button>
              <button
                className={`tab-btn ${activeTab === 'congKhai' ? 'active' : ''}`}
                onClick={() => setActiveTab('congKhai')}
              >
                Hồ sơ công khai
              </button>
            </div>
          </div>

          {/* === TAB 1: THÔNG TIN CÁ NHÂN === */}
          {activeTab === 'caNhan' && (
            <div className="card">
              <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span>📋 Thông tin cá nhân</span>
                {!editing ? (
                  <button className="btn btn-outline btn-sm" onClick={() => setEditing(true)}>✏️ Chỉnh sửa</button>
                ) : (
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button className="btn btn-primary btn-sm" onClick={handleSaveCaNhan} disabled={saving}>
                      {saving ? '⏳' : '💾 Lưu'}
                    </button>
                    <button className="btn btn-secondary btn-sm" onClick={() => setEditing(false)}>Hủy</button>
                  </div>
                )}
              </div>
              <div className="card-body">
                {editing ? (
                  <>
                    <div className="form-group">
                      <label className="form-label">Họ và tên</label>
                      <input className="form-control" value={formCaNhan.hoTen} onChange={e => setFormCaNhan(f => ({ ...f, hoTen: e.target.value }))} />
                    </div>
                    <div className="form-group">
                      <label className="form-label">Số điện thoại</label>
                      <input className="form-control" value={formCaNhan.soDienThoai} onChange={e => setFormCaNhan(f => ({ ...f, soDienThoai: e.target.value }))} />
                    </div>
                  </>
                ) : (
                  <div>
                    {infoCaNhan.map(([label, value]) => (
                      <div key={label} className="info-row">
                        <span style={{ color: 'var(--text-muted)' }}>{label}</span>
                        <strong>{value}</strong>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* === TAB 2: HỒ SƠ CÔNG KHAI === */}
          {activeTab === 'congKhai' && (
            <div className="card">
              <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span>🌐 Hồ sơ công khai</span>
                {!editing ? (
                  <button className="btn btn-outline btn-sm" onClick={() => setEditing(true)}>✏️ Chỉnh sửa</button>
                ) : (
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button className="btn btn-primary btn-sm" onClick={handleSaveCongKhai} disabled={saving}>
                      {saving ? '⏳' : '💾 Lưu'}
                    </button>
                    <button className="btn btn-secondary btn-sm" onClick={() => setEditing(false)}>Hủy</button>
                  </div>
                )}
              </div>
              <div className="card-body">
                {editing ? (
                  <>
                    <div className="form-group">
                      <label className="form-label">Giới thiệu bản thân</label>
                      <textarea
                        className="form-control"
                        rows={4}
                        value={formCongKhai.gioiThieu}
                        onChange={e => setFormCongKhai(f => ({ ...f, gioiThieu: e.target.value }))}
                        placeholder="Viết vài dòng giới thiệu về bạn..."
                      />
                    </div>

                    <div className="form-group">
                      <label className="form-label">Nghề nghiệp</label>
                      <input
                        className="form-control"
                        value={formCongKhai.ngheNghiep}
                        onChange={e => setFormCongKhai(f => ({ ...f, ngheNghiep: e.target.value }))}
                      />
                    </div>

                    <div className="form-group">
                      <label className="form-label">Địa chỉ</label>
                      <input
                        className="form-control"
                        value={formCongKhai.diaChi}
                        onChange={e => setFormCongKhai(f => ({ ...f, diaChi: e.target.value }))}
                      />
                    </div>

                    <div className="form-row">
                      <div className="form-group" style={{ flex: 1 }}>
                        <label className="form-label">Ngày sinh</label>
                        <input
                          type="date"
                          className="form-control"
                          value={formCongKhai.ngaySinh}
                          onChange={e => setFormCongKhai(f => ({ ...f, ngaySinh: e.target.value }))}
                        />
                      </div>
                      <div className="form-group" style={{ flex: 1 }}>
                        <label className="form-label">Giới tính</label>
                        <select
                          className="form-control"
                          value={formCongKhai.gioiTinh}
                          onChange={e => setFormCongKhai(f => ({ ...f, gioiTinh: e.target.value }))}
                        >
                          <option value="">Chọn giới tính</option>
                          <option value="Nam">Nam</option>
                          <option value="Nữ">Nữ</option>
                          <option value="Khác">Khác</option>
                        </select>
                      </div>
                    </div>
                  </>
                ) : (
                  <div>
                    <div className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>Giới thiệu</span>
                      <strong>{user?.gioiThieu || 'Chưa có giới thiệu'}</strong>
                    </div>
                    <div className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>Nghề nghiệp</span>
                      <strong>{user?.ngheNghiep || 'Chưa cập nhật'}</strong>
                    </div>
                    <div className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>Địa chỉ</span>
                      <strong>{user?.diaChi || 'Chưa cập nhật'}</strong>
                    </div>
                    <div className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>Ngày sinh</span>
                      <strong>{user?.ngaySinh ? new Date(user.ngaySinh).toLocaleDateString('vi-VN') : 'Chưa cập nhật'}</strong>
                    </div>
                    <div className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>Giới tính</span>
                      <strong>{user?.gioiTinh || 'Chưa cập nhật'}</strong>
                    </div>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Hành động nhanh */}
          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header">⚡ Hành động nhanh</div>
            <div className="card-body">
              <div className="quick-actions">
                {quickActions.map(({ to, icon, label }) => (
                  <Link key={to} to={to} className="quick-action-btn">
                    <span>{icon}</span>
                    <span>{label}</span>
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
